module top_module(
    input [7:0] d_in,
    input [2:0] shift_amount,
    input clk,
    output [7:0] d_out
);reg [7:0] unshifted_d_out;

    always @ (posedge clk) begin
        case (shift_amount)
            3'b000: unshifted_d_out <= d_in;
            3'b001: unshifted_d_out <= {d_in[6:0], 1'b0};
            3'b010: unshifted_d_out <= {d_in[5:0], 2'b00};
            3'b011: unshifted_d_out <= {d_in[4:0], 3'b000};
            3'b100: unshifted_d_out <= {d_in[3:0], 4'b0000};
            3'b101: unshifted_d_out <= {d_in[2:0], 5'b00000};
            3'b110: unshifted_d_out <= {d_in[1:0], 6'b000000};
            3'b111: unshifted_d_out <= {d_in[0], 7'b0000000};
        endcase
    end

    assign d_out = unshifted_d_out;

endmodule
